--
Дан код: @AGI 0.0.1;

program clients_claw;
system samples;
module claw;

procedure call(data) {
	var authentication := data.authentication;

	if !authentication.isAuthenticated return;

	var command := data.command;
	var socket1 := socket;

	switch command {
		if "hello_world"
			print(#"Hello world from Claw {socket1.name}");
	}
}

procedure Main() {
	var vault1 := vault;
	var port := vault1.read("port");
	var credentials := vault1.read("credentials");

	var claw1 := stream<claw>;
	claw1.open({
		port: port,
		authentication: {
			credentials: credentials
		}
	});
	claw1.methods.add("call", &call);
}

entrypoint {
	Main;
},
напиши компилятор и интерпретатор на код.
добавь устройство claw: это сокет сервер слушающий заданный порт.
протокол получает на вход json, возвращает json.
credentials задают логин и пароль: [{user, password}]
сделай ему POST /authenticate {user,password} => {token}, с проверкой безпасности: если неверный логин или пароль блокировка на (10сек, 30сек, 1мин, 5мин, 15мин, 30мин, 1ч, 1д, навсегда) с нарастанием.
также он содержит methods и можно связать по имени на функцию.
POST beareauth /entrypoint {
method
data: {
command
object
method
args: [...]
}
}
&call: означает адрес процедуры call

новый блок: switch command {
		if "hello_world"
			print(#"Hello world from Claw {socket1.name}");
	}
примеры: switch arg0, arg1... {
   if value01 {
   }
   if value02 {
   }
   if 0: value0, 1: value1, ... {
   }
}
также claw умеет пробрасывать объекты в вызываемые методы
например в процедуре call доступен socket через: var socket1 := socket;

