                if (root.TryGetProperty("data", out var d)) data = JsonElementToObject(d);
            }
            catch
            {
                await WriteJsonResponse(resp, 400, new Dictionary<string, object> { ["error"] = "Invalid JSON" }).ConfigureAwait(false);
                return;
            }

